SELECT time, device_id, device_code,
       accel_x, accel_y, accel_z,
       gyro_x, gyro_y, gyro_z,
       sequence, battery_level, motion_type, step_count
FROM device_imu_data
WHERE device_code = #{deviceCode}
  AND time >= #{beginTime}
  AND time <= #{endTime}
ORDER BY time ASC

SELECT COUNT(1)
FROM device_imu_data
WHERE device_code = #{deviceCode}
  AND time >= #{beginTime}
  AND time <= #{endTime}
